"""Method generation logic for dynamic API methods."""

import importlib
import logging
import re
from dataclasses import dataclass
from typing import Any, Callable, Dict, Optional, Tuple, Type

from ..exceptions import GreenNodeRequestError
from .logging import configure_logger


@dataclass
class PreparedRequest:
    """Holds a prepared HTTP request (no I/O performed)."""

    url: str
    method: str
    query_params: Dict[str, Any]
    headers: Optional[Dict[str, str]]
    body: Optional[Any]


def get_model_class(module_path: str, model_name: str) -> Type[Any]:
    """Dynamically import a model class.

    Args:
        module_path: Full module path (e.g., "greennode_agentbase.identity.models")
        model_name: Name of the model class (e.g., "AgentIdentityResponse")

    Returns:
        The model class

    Raises:
        ImportError: If the module or class cannot be imported
    """
    try:
        module = importlib.import_module(module_path)
        model_class = getattr(module, model_name)
        return model_class
    except (ImportError, AttributeError) as e:
        raise ImportError(
            f"Cannot import {model_name} from {module_path}: {e}"
        ) from e


def build_url(path_template: str, path_params: Dict[str, Any]) -> str:
    """Build URL from template and path parameters.

    Args:
        path_template: URL template with placeholders (e.g., "/api/v1/agent-identities/{name}")
        path_params: Dictionary of path parameters

    Returns:
        Built URL with parameters substituted
    """
    url = path_template
    for key, value in path_params.items():
        placeholder = f"{{{key}}}"
        if placeholder not in url:
            raise ValueError(
                f"Path parameter '{key}' not found in template '{path_template}'"
            )
        url = url.replace(placeholder, str(value))
    return url


def extract_path_params(
    path_template: str, kwargs: Dict[str, Any]
) -> Tuple[Dict[str, Any], Dict[str, Any]]:
    """Extract path parameters from kwargs based on template.

    Args:
        path_template: URL template with placeholders
        kwargs: All keyword arguments

    Returns:
        Tuple of (path_params, remaining_kwargs)
    """
    placeholders = re.findall(r"{(\w+)}", path_template)
    path_params = {}
    remaining = kwargs.copy()

    for placeholder in placeholders:
        if placeholder in remaining:
            path_params[placeholder] = remaining.pop(placeholder)

    return path_params, remaining


def prepare_request(
    path_template: str,
    method: str,
    params_spec: Dict[str, Any],
    kwargs: Dict[str, Any],
    operation_name: str,
) -> PreparedRequest:
    """Pure sync request preparation. No I/O.

    Args:
        path_template: URL template with placeholders
        method: HTTP method (GET, POST, PUT, PATCH, DELETE)
        params_spec: Params spec from operation (query, header, body)
        kwargs: All keyword arguments
        operation_name: Operation name for error messages

    Returns:
        PreparedRequest with url, method, query_params, headers, body
    """
    path_params, remaining = extract_path_params(path_template, kwargs)
    url = build_url(path_template, path_params)

    query_params: Dict[str, Any] = {}
    query_param_names = params_spec.get("query", [])
    for param_name in query_param_names:
        if param_name in remaining:
            query_params[param_name] = remaining.pop(param_name)

    header_params: Dict[str, str] = {}
    header_param_names = params_spec.get("header", [])
    for param_name in header_param_names:
        if param_name in remaining:
            value = remaining.pop(param_name)
            header_params[param_name] = str(value) if value is not None else ""

    request_body: Optional[Any] = None
    body_spec = params_spec.get("body")
    if body_spec:
        if isinstance(body_spec, dict):
            if body_spec.get("is_array"):
                body_model_name = body_spec.get("model")
                body_module = body_spec.get("module")
                body_value = None
                for key in ["request", "body", "data", *remaining.keys()]:
                    if key in remaining:
                        body_value = remaining.pop(key)
                        break

                if body_value is None:
                    raise ValueError(f"Missing required body parameter for {operation_name}")

                if body_model_name and body_module and isinstance(body_value, list):
                    body_model_class = get_model_class(body_module, body_model_name)
                    request_body = [
                        item.model_dump(by_alias=True)
                        if isinstance(item, body_model_class)
                        else body_model_class(**item).model_dump(by_alias=True)
                        if isinstance(item, dict)
                        else item
                        for item in body_value
                    ]
                else:
                    request_body = body_value
            else:
                body_model_name = body_spec.get("model")
                body_module = body_spec.get("module")
                if body_model_name and body_module:
                    body_model_class = get_model_class(body_module, body_model_name)
                    body_value = None
                    for key in ["request", body_model_name.lower(), *remaining.keys()]:
                        if key in remaining:
                            body_value = remaining.pop(key)
                            break

                    if body_value is None:
                        try:
                            body_value = body_model_class(**remaining)
                        except Exception:
                            raise ValueError(
                                f"Missing required body parameter for {operation_name}"
                            )
                    elif not isinstance(body_value, body_model_class):
                        body_value = body_model_class(**body_value)

                    request_body = body_value.model_dump(by_alias=True)
        else:
            for key in list(remaining.keys()):
                request_body = remaining.pop(key)
                break

    return PreparedRequest(
        url=url,
        method=method,
        query_params=query_params,
        headers=header_params if header_params else None,
        body=request_body,
    )


def parse_response(
    response_data: Any,
    response_model: Optional[Type[Any]],
    is_array_response: bool,
) -> Any:
    """Convert raw response to model(s) or return as-is.

    Args:
        response_data: Raw response from HTTP client
        response_model: Optional model class to parse into
        is_array_response: Whether response is a list of models

    Returns:
        Parsed response (model instance, list of models, or raw data)
    """
    if response_model:
        if is_array_response and isinstance(response_data, list):
            return [
                response_model(**item) if isinstance(item, dict) else item
                for item in response_data
            ]
        if isinstance(response_data, dict):
            return response_model(**response_data)
    return response_data


async def async_execute(
    prepared: PreparedRequest,
    http_client: Any,
    ensure_authenticated: Optional[Callable[[], Any]],
    response_model: Optional[Type[Any]],
    is_array_response: bool,
    operation_name: str,
) -> Any:
    """Execute prepared request asynchronously.

    Args:
        prepared: PreparedRequest from prepare_request()
        http_client: HTTP client with async get/post/put/patch/delete
        ensure_authenticated: Optional async callable for auth
        response_model: Optional model class for response parsing
        is_array_response: Whether response is a list
        operation_name: For error messages

    Returns:
        Parsed response
    """
    if ensure_authenticated:
        await ensure_authenticated()

    try:
        request_headers = prepared.headers
        query_params = (
            prepared.query_params if prepared.query_params else None
        )
        if prepared.method == "GET":
            response_data = await http_client.get(
                prepared.url,
                params=query_params,
                headers=request_headers,
            )
        elif prepared.method == "POST":
            if prepared.body is not None:
                response_data = await http_client.post(
                    prepared.url,
                    json=prepared.body,
                    headers=request_headers,
                    params=query_params,
                )
            else:
                response_data = await http_client.post(
                    prepared.url,
                    headers=request_headers,
                    params=query_params,
                )
        elif prepared.method == "PUT":
            if prepared.body is not None:
                response_data = await http_client.put(
                    prepared.url,
                    json=prepared.body,
                    headers=request_headers,
                    params=query_params,
                )
            else:
                response_data = await http_client.put(
                    prepared.url,
                    headers=request_headers,
                    params=query_params,
                )
        elif prepared.method == "PATCH":
            if prepared.body is not None:
                response_data = await http_client.patch(
                    prepared.url,
                    json=prepared.body,
                    headers=request_headers,
                    params=query_params,
                )
            else:
                response_data = await http_client.patch(
                    prepared.url,
                    headers=request_headers,
                    params=query_params,
                )
        elif prepared.method == "DELETE":
            response_data = await http_client.delete(
                prepared.url,
                headers=request_headers,
                params=query_params,
            )
        else:
            raise ValueError(f"Unsupported HTTP method: {prepared.method}")

        return parse_response(response_data, response_model, is_array_response)

    except Exception as e:
        if isinstance(e, GreenNodeRequestError):
            raise
        raise GreenNodeRequestError(
            f"Request failed for {operation_name}: {str(e)}", cause=e
        ) from e


def sync_execute(
    prepared: PreparedRequest,
    http_client: Any,
    ensure_authenticated_sync: Optional[Callable[[], None]],
    response_model: Optional[Type[Any]],
    is_array_response: bool,
    operation_name: str,
) -> Any:
    """Execute prepared request synchronously. Does not touch async code.

    Args:
        prepared: PreparedRequest from prepare_request()
        http_client: HTTP client with get_sync/post_sync/put_sync/patch_sync/delete_sync
        ensure_authenticated_sync: Optional sync callable for auth
        response_model: Optional model class for response parsing
        is_array_response: Whether response is a list
        operation_name: For error messages

    Returns:
        Parsed response
    """
    if ensure_authenticated_sync:
        ensure_authenticated_sync()

    try:
        request_headers = prepared.headers
        query_params = (
            prepared.query_params if prepared.query_params else None
        )
        if prepared.method == "GET":
            response_data = http_client.get_sync(
                prepared.url,
                params=query_params,
                headers=request_headers,
            )
        elif prepared.method == "POST":
            if prepared.body is not None:
                response_data = http_client.post_sync(
                    prepared.url,
                    json=prepared.body,
                    headers=request_headers,
                    params=query_params,
                )
            else:
                response_data = http_client.post_sync(
                    prepared.url,
                    headers=request_headers,
                    params=query_params,
                )
        elif prepared.method == "PUT":
            if prepared.body is not None:
                response_data = http_client.put_sync(
                    prepared.url,
                    json=prepared.body,
                    headers=request_headers,
                    params=query_params,
                )
            else:
                response_data = http_client.put_sync(
                    prepared.url,
                    headers=request_headers,
                    params=query_params,
                )
        elif prepared.method == "PATCH":
            if prepared.body is not None:
                response_data = http_client.patch_sync(
                    prepared.url,
                    json=prepared.body,
                    headers=request_headers,
                    params=query_params,
                )
            else:
                response_data = http_client.patch_sync(
                    prepared.url,
                    headers=request_headers,
                    params=query_params,
                )
        elif prepared.method == "DELETE":
            response_data = http_client.delete_sync(
                prepared.url,
                headers=request_headers,
                params=query_params,
            )
        else:
            raise ValueError(f"Unsupported HTTP method: {prepared.method}")

        return parse_response(response_data, response_model, is_array_response)

    except Exception as e:
        if isinstance(e, GreenNodeRequestError):
            raise
        raise GreenNodeRequestError(
            f"Request failed for {operation_name}: {str(e)}", cause=e
        ) from e


def generate_method(
    operation_name: str,
    operation_spec: Dict[str, Any],
    http_client: Any,
    base_url: str,
    ensure_authenticated: Optional[Callable[[], Any]] = None,
    ensure_authenticated_sync: Optional[Callable[[], None]] = None,
) -> Callable[..., Any]:
    """Generate a dynamic method for an API operation.

    Args:
        operation_name: Name of the operation (e.g., "get_agent_identity_async")
        operation_spec: Operation specification from API model
        http_client: HTTP client instance (must implement HTTPClientProtocol)
        base_url: Base URL for the API
        ensure_authenticated: Optional async callable to ensure authentication
        ensure_authenticated_sync: Optional sync callable to ensure authentication for sync requests

    Returns:
        Generated method function
    """
    method = operation_spec["method"]
    path_template = operation_spec["path"]
    params_spec = operation_spec.get("params", {})
    response_model_name = operation_spec.get("response_model")
    response_module = operation_spec.get("module")
    is_array_response = operation_spec.get("is_array_response", False)
    is_async = operation_spec.get("async", False)

    # Get response model class if specified
    response_model = None
    if response_model_name and response_module:
        try:
            response_model = get_model_class(response_module, response_model_name)
        except ImportError as e:
            logger = logging.getLogger("greennode_agentbase.core")
            configure_logger(logger)
            logger.warning(f"Could not import response model {response_model_name}: {e}")

    async def async_method(**kwargs: Any) -> Any:
        """Generated async method."""
        prepared = prepare_request(
            path_template, method, params_spec, kwargs, operation_name
        )
        return await async_execute(
            prepared=prepared,
            http_client=http_client,
            ensure_authenticated=ensure_authenticated,
            response_model=response_model,
            is_array_response=is_array_response,
            operation_name=operation_name,
        )

    def sync_method(**kwargs: Any) -> Any:
        """Generated sync method. Does not touch async code."""
        prepared = prepare_request(
            path_template, method, params_spec, kwargs, operation_name
        )
        return sync_execute(
            prepared=prepared,
            http_client=http_client,
            ensure_authenticated_sync=ensure_authenticated_sync,
            response_model=response_model,
            is_array_response=is_array_response,
            operation_name=operation_name,
        )

    if is_async:
        return async_method
    return sync_method

